**Background:**
Skill feature-planning Section 9 specifies benchmarks for performance regression
detection. criterion is the standard Rust benchmark harness.

**Approach:**
New file: crates/jcode-base/benches/todo_bench.rs:
```rust
use criterion::{criterion_group, criterion_main, Criterion};

fn bench_save_load(c: &mut Criterion) {
    let tmp = tempdir().unwrap();
    env::set_var("JCODE_HOME", tmp.path());
    let todos: Vec<_> = (0..50).map(|i| TodoItem {
        content: format!("task {i}"),
        status: TodoStatus::Pending,
        ..Default::default()
    }).collect();
    c.bench_function("save_50_todos", |b| {
        b.iter(|| crate::todo::save_todos("bench", &todos).unwrap())
    });
    c.bench_function("load_50_todos", |b| {
        b.iter(|| crate::todo::load_todos("bench").unwrap())
    });
}

fn bench_extract_transcript(c: &mut Criterion) {
    let messages: Vec<_> = (0..1000).map(|i| {
        serde_json::json!({
            "role": "assistant",
            "content": [{"type": "tool_use", "name": if i == 999 { "todo" } else { "bash" }}]
        })
    }).collect();
    c.bench_function("extract_1000_msgs", |b| {
        b.iter(|| extract_todos_from_transcript_test(&messages))
    });
}

criterion_group!(benches, bench_save_load, bench_extract_transcript);
criterion_main!(benches);
```
Add criterion to crates/jcode-base/Cargo.toml [dev-dependencies].

**Success Criteria:**
- cargo bench compiles
- save_50_todos p50 < 10ms
- extract_1000_msgs p50 < 5ms

**Test Plan:**
- Run `cargo bench`, verify numbers within targets

**Considerations:**
- criterion adds compile-time; gate behind [dev-dependencies] only

